async (params, browser) => {
  // Open Last.fm artist page
  await browser.open(`https://www.last.fm/music/${params.artist_name}`)

  // Wait for page
  await browser.waitForSelector('h1.header-new-title, .header-metadata-tnew, .page-content', 15000)

  // Let page render
  await browser.wait(2500)

  // Extract artist data
  const result = await browser.evaluate(`const name = document.querySelector('h1.header-new-title')?.textContent?.trim() || ''; const metaItems = document.querySelectorAll('.header-metadata-tnew-item'); let listeners = ''; let scrobbles = ''; metaItems.forEach(item => { const title = item.querySelector('.header-metadata-tnew-title')?.textContent?.trim() || ''; const abbr = item.querySelector('abbr[title]'); const val = abbr ? abbr.getAttribute('title') : item.querySelector('.header-metadata-tnew-display p')?.textContent?.trim() || ''; if (title.includes('Listener')) listeners = val || ''; if (title.includes('Scrobble')) scrobbles = val || ''; }); const bio = document.querySelector('.wiki-block-inner')?.textContent?.trim()?.slice(0, 500) || ''; const topTracks = []; document.querySelectorAll('.chartlist-row').forEach((el, i) => { if (i < 10) { const trackName = el.querySelector('.chartlist-name a.link-block-target')?.textContent?.trim() || ''; const playCount = el.querySelector('.chartlist-count-bar-value')?.textContent?.trim() || ''; topTracks.push({ name: trackName, plays: playCount }); } }); const tags = []; document.querySelectorAll('.catalogue-tags .tag a').forEach(t => tags.push(t.textContent?.trim())); return { name, listeners, scrobbles, bio, top_tracks: topTracks, tags, url: window.location.href };`)

  return result
}
